// Способ 1: Convert.ToInt32()

Console.WriteLine("Введите целое число:");

string text = Console.ReadLine();
int number = Convert.ToInt32(text);

Console.WriteLine(number + 5);

// Способ 2: int.Parse()

Console.WriteLine("Введите целое число:");

string text = Console.ReadLine();
int number = int.Parse(text);

Console.WriteLine(number + 5);

// Способ 1: Convert.ToDouble()

Console.WriteLine("Введите дробное число:");

string text = Console.ReadLine();
double number = Convert.ToDouble(text);

Console.WriteLine(number * 2);

// Способ 2: double.Parse()

Console.WriteLine("Введите дробное число:");

string text = Console.ReadLine();
double number = double.Parse(text);

Console.WriteLine(number * 2);

// int → string

int number = 10;

string text = number.ToString();

Console.WriteLine(text);

// double → string

double pi = 3.14159;

string textDouble = pi.ToString();

Console.WriteLine(textDouble);

// while

int i = 0;

while(i < 5)
{
    Console.WriteLine(i);
    i++;
}

// do while

int j = 0;

do
{
    Console.WriteLine(j);
    j++;
} while(j < 5);

// Рандом от 0 до 2147483647

Random r = new Random();

int number = r.Next();

Console.WriteLine(number);

// Рандом от 0 до 4

Random r = new Random();

int number = r.Next(5);

Console.WriteLine(number);

// Рандом от 1 до 9

Random r = new Random();

int number = r.Next(1, 10);

Console.WriteLine(number);

// Рандом [0; 1)

Random r = new Random();

double n = r.NextDouble();

Console.WriteLine(n);

// Рандом - [0; 10)

